import React, { useState } from 'react';
import { Industry, Language } from '../types';
import { TRANSLATIONS } from '../constants';

interface ROICalculatorProps {
  lang: Language;
}

const ROICalculator: React.FC<ROICalculatorProps> = ({ lang }) => {
  const [industry, setIndustry] = useState<Industry>('CORPORATE');
  const [volume, setVolume] = useState<number>(100); // e.g., employees, members, rooms
  const [hoursPerWeek, setHoursPerWeek] = useState<number>(15);

  const calculateSavings = () => {
    // Basic logic: 60% time reduction via automation
    const timeSavedPerMonth = (hoursPerWeek * 4) * 0.6;
    const avgHourlyRate = 25; // USD/hr base assumption
    const moneySaved = timeSavedPerMonth * avgHourlyRate * (volume / 10);
    return {
      hours: Math.round(timeSavedPerMonth),
      money: Math.round(moneySaved).toLocaleString()
    };
  };

  const results = calculateSavings();
  const t = TRANSLATIONS[lang];

  return (
    <section id="roi" className="py-24 bg-[#020617]">
      <div className="max-w-7xl mx-auto px-4 md:px-8">
        <div className="glass p-8 md:p-12 rounded-[2.5rem] border border-cyan-500/10 grid grid-cols-1 lg:grid-cols-2 gap-16 items-center">
          <div>
            <h3 className="text-electric-cyan font-bold uppercase tracking-[0.2em] text-sm mb-4">
              Real Impact
            </h3>
            <h2 className="text-3xl md:text-5xl font-bold text-white mb-6">
              {t.roiTitle}
            </h2>
            <p className="text-slate-400 mb-10">
              {t.roiSubtext}
            </p>

            <div className="space-y-8">
              <div>
                <label className="text-sm font-medium text-slate-300 block mb-3 uppercase tracking-wider">Select Industry</label>
                <div className="grid grid-cols-2 gap-3">
                  {['CHURCH', 'SCHOOL', 'HOTEL', 'CORPORATE'].map((ind) => (
                    <button
                      key={ind}
                      onClick={() => setIndustry(ind as Industry)}
                      className={`px-4 py-3 rounded-xl text-xs font-bold transition-all border ${
                        industry === ind 
                        ? 'bg-electric-cyan text-slate-950 border-electric-cyan shadow-[0_0_20px_rgba(34,211,238,0.2)]' 
                        : 'bg-white/5 text-slate-400 border-white/10 hover:border-white/20'
                      }`}
                    >
                      {ind}
                    </button>
                  ))}
                </div>
              </div>

              <div>
                <div className="flex justify-between items-center mb-4">
                  <label className="text-sm font-medium text-slate-300 uppercase tracking-wider">
                    {industry === 'CHURCH' ? 'Total Members' : industry === 'SCHOOL' ? 'Total Students' : industry === 'HOTEL' ? 'Total Rooms' : 'Total Employees'}
                  </label>
                  <span className="text-electric-cyan font-bold">{volume}</span>
                </div>
                <input 
                  type="range" 
                  min="10" max="5000" step="10"
                  value={volume}
                  onChange={(e) => setVolume(Number(e.target.value))}
                  className="w-full accent-electric-cyan"
                />
              </div>

              <div>
                <div className="flex justify-between items-center mb-4">
                  <label className="text-sm font-medium text-slate-300 uppercase tracking-wider">Current Manual Hours/Week</label>
                  <span className="text-electric-cyan font-bold">{hoursPerWeek}h</span>
                </div>
                <input 
                  type="range" 
                  min="1" max="60" step="1"
                  value={hoursPerWeek}
                  onChange={(e) => setHoursPerWeek(Number(e.target.value))}
                  className="w-full accent-electric-cyan"
                />
              </div>
            </div>
          </div>

          <div className="bg-[#0B1120] rounded-[2rem] p-10 border border-white/5 relative overflow-hidden flex flex-col justify-center items-center text-center">
            <div className="absolute top-0 right-0 w-32 h-32 bg-cyan-500/5 blur-3xl rounded-full"></div>

            <div className="mb-8">
              <p className="text-slate-400 text-sm uppercase tracking-widest mb-2 font-medium">Estimated Monthly Savings</p>
              <div className="text-6xl md:text-7xl font-bold text-white tracking-tighter">
                <span className="text-electric-cyan">$</span>{results.money}
              </div>
            </div>

            <div className="w-full h-px bg-white/10 my-8"></div>

            <div className="grid grid-cols-2 gap-8 w-full">
              <div>
                <div className="text-3xl font-bold text-white mb-1">{results.hours}h</div>
                <p className="text-[10px] text-slate-500 uppercase tracking-widest">Saved Monthly</p>
              </div>
              <div>
                <div className="text-3xl font-bold text-white mb-1">60%</div>
                <p className="text-[10px] text-slate-500 uppercase tracking-widest">Efficiency Boost</p>
              </div>
            </div>

            <button className="mt-12 w-full py-4 bg-gradient-to-r from-cyan-500 to-cyan-600 text-slate-950 font-bold rounded-xl hover:shadow-[0_0_40px_rgba(34,211,238,0.4)] transition-all">
