    { role: 'model', text: 'Hello! I am Lexon AI. How can I help automate your business today? / Habari! Mimi ni Lexon AI. Nawezaje kusaidia kurahisisha biashara yako leo?' }
  ]);
  const [input, setInput] = useState('');
  const [loading, setLoading] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages]);

  const handleSend = async () => {
    if (!input.trim() || loading) return;

    const userMsg = input;
    setInput('');
    setMessages(prev => [...prev, { role: 'user', text: userMsg }]);
    setLoading(true);

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: [...messages, { role: 'user', text: userMsg }].map(m => ({
          role: m.role,
          parts: [{ text: m.text }]
        })),
        config: {
          systemInstruction: `You are Lexon AI, a professional business automation consultant for Lexon Tech Solutions Co. Ltd. 
          Your goal is to explain Lexon's products: 
          1. Lexon Grace (Church automation: tithes, members, SMS).
          2. Lexon Academic (School management: results, fees, portals).
          3. Lexon Stay (Hotel booking, inventory, billing).
          4. Corporate ERP (Custom sales, staff, and productivity tracking).
          5. Premium Web Design.
          Focus on ROI and business efficiency. 
          Respond in the language the user uses (English or Swahili). 
          IMPORTANT: At the end of every helpful response or when a user is interested in a demo/quote, strictly invite them to call or WhatsApp the CEO at ${CONTACT_NUMBER}.`,
        },
      });

      const aiText = response.text || "I'm sorry, I'm having trouble connecting. Please call us at " + CONTACT_NUMBER;
      setMessages(prev => [...prev, { role: 'model', text: aiText }]);
    } catch (error) {
      setMessages(prev => [...prev, { role: 'model', text: "Error connecting to AI. Please contact us directly at " + CONTACT_NUMBER }]);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="fixed bottom-6 right-6 z-[100] font-sans">
      {!isOpen ? (
        <button 
          onClick={() => setIsOpen(true)}
          className="w-16 h-16 bg-electric-cyan text-slate-950 rounded-full flex items-center justify-center shadow-[0_0_30px_rgba(34,211,238,0.4)] hover:scale-110 transition-transform animate-bounce"
        >
          <MessageSquare size={28} />
        </button>
      ) : (
        <div className="w-[90vw] md:w-[400px] h-[500px] glass rounded-3xl flex flex-col shadow-2xl border border-white/10 overflow-hidden">
          {/* Header */}
          <div className="bg-electric-cyan p-4 flex justify-between items-center">
            <div className="flex items-center gap-3">
              <div className="w-10 h-10 bg-slate-950 rounded-full flex items-center justify-center">
                <Bot className="text-electric-cyan" size={20} />
              </div>
              <div>
                <h3 className="text-slate-950 font-bold text-sm">Lexon AI Assistant</h3>
                <span className="text-slate-900 text-[10px] uppercase font-bold tracking-widest">Always Online</span>
              </div>
            </div>
            <button onClick={() => setIsOpen(false)} className="text-slate-950 hover:bg-slate-950/10 p-1 rounded-lg">
              <X size={20} />
            </button>
          </div>

          {/* Messages */}
          <div ref={scrollRef} className="flex-grow overflow-y-auto p-4 space-y-4 bg-slate-950/50">
            {messages.map((m, i) => (
              <div key={i} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'}`}>
                <div className={`max-w-[80%] p-3 rounded-2xl text-sm ${
                  m.role === 'user' 
                  ? 'bg-white/10 text-white rounded-tr-none' 
                  : 'bg-electric-cyan/10 text-slate-200 border border-electric-cyan/20 rounded-tl-none'
                }`}>
                  {m.text}
                </div>
              </div>
            ))}
            {loading && (
              <div className="flex justify-start">
                <div className="bg-electric-cyan/10 p-3 rounded-2xl animate-pulse text-xs text-electric-cyan">
                  AI is thinking...
                </div>
              </div>
            )}
          </div>

          {/* Input */}
          <div className="p-4 border-t border-white/5 bg-slate-950 flex gap-2">
            <input 
              value={input}
              onChange={(e) => setInput(e.target.value)}
              onKeyDown={(e) => e.key === 'Enter' && handleSend()}
              placeholder="Ask about automation..."
              className="flex-grow bg-white/5 border border-white/10 rounded-xl px-4 py-2 text-sm focus:outline-none focus:border-electric-cyan transition-colors"
            />
            <button 
              onClick={handleSend}
              className="bg-electric-cyan text-slate-950 p-2 rounded-xl hover:scale-105 transition-transform"
            >
              <Send size={18} />
            </button>
          </div>

          <div className="px-4 py-2 bg-slate-900 text-[10px] text-center text-slate-500 border-t border-white/5 flex items-center justify-center gap-2">
            <Phone size={10} /> Call us: {CONTACT_NUMBER}
          </div>
        </div>
      )}
    </div>
  );
};

