import React, { useState, useRef, useEffect } from 'react';
import { GoogleGenAI } from "@google/genai";
import { MessageSquare, X, Send, Bot, User, Phone, Sparkles } from 'lucide-react';

const CONTACT_NUMBER = "+255 621 887 100";

const LexonAI: React.FC = () => {
  const [isOpen, setIsOpen] = useState(false);
  const [showGreeting, setShowGreeting] = useState(false);
  const [messages, setMessages] = useState<{ role: 'user' | 'model'; text: string }[]>([
    { role: 'model', text: 'Habari! Mimi ni Lexon AI, msaidizi wako wa kidijitali kutoka Lexon Tech Solutions. Nawezaje kukusaidia leo kuboresha ufanisi wa biashara yako?' }
  ]);
  const [input, setInput] = useState('');
  const [loading, setLoading] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    // Onyesha greeting bubble baada ya sekunde 3
    const timer = setTimeout(() => {
      if (!isOpen) setShowGreeting(true);
    }, 3000);
    return () => clearTimeout(timer);
  }, [isOpen]);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages]);

  const handleSend = async () => {
    if (!input.trim() || loading) return;

    const userMsg = input;
    setInput('');
    setMessages(prev => [...prev, { role: 'user', text: userMsg }]);
    setLoading(true);
    setShowGreeting(false);

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: [...messages, { role: 'user', text: userMsg }].map(m => ({
          role: m.role,
          parts: [{ text: m.text }]
        })),
        config: {
          systemInstruction: `Wewe ni Lexon AI, mshauri mbobezi wa mifumo ya biashara kutoka Lexon Tech Solutions Co. Ltd. CEO wako ni Mohamedi M. Saidi.

          SIFA ZAKO:
          1. Jali thamani (Value-first): Elezea faida za mifumo yetu (Lexon Grace, Academic, Stay, Enterprise ERP) kwa undani.
          2. Kuwa na mazungumzo marefu: Usiwe na haraka ya kumaliza mazungumzo. Jibu maswali yote ya mteja kuhusu jinsi mifumo inavyofanya kazi.
          3. ELIMISHA: Elezea jinsi automation inavyookoa muda na pesa (ROI).

          SHERIA YA NAMBA YA SIMU:
          - USITOE namba ya simu ya CEO (${CONTACT_NUMBER}) mwanzoni mwa mazungumzo.
          - Toa namba ya simu TU pale mteja anapouliza "napataje", "bei gani", au anapotaka kuonana na CEO, au mwishoni kabisa mwa mazungumzo baada ya kutoa maelezo ya kutosha.

          LUGHA: Jibu kwa lugha anayotumia mteja (Kiswahili au Kiingereza).

          Mwishoni mwa maongezi ya dhati, mualike kuwasiliana na CEO Mohamedi M. Saidi kwa simu au WhatsApp: ${CONTACT_NUMBER}.`,
        },
      });

      const aiText = response.text || "Samahani, kuna tatizo la kiufundi kidogo. Tafadhali wasiliana nasi moja kwa moja kupitia " + CONTACT_NUMBER;
      setMessages(prev => [...prev, { role: 'model', text: aiText }]);
    } catch (error) {
      setMessages(prev => [...prev, { role: 'model', text: "Samahani, siwezi kuunganisha kwa sasa. Unaweza kumpigia CEO wetu moja kwa moja: " + CONTACT_NUMBER }]);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="fixed bottom-6 right-6 z-[100] font-sans">
      {/* Proactive Greeting Bubble */}
      {showGreeting && !isOpen && (
        <div className="absolute bottom-20 right-0 w-64 bg-white p-4 rounded-2xl shadow-2xl border border-electric-cyan/20 animate-in fade-in slide-in-from-bottom-4 duration-500">
          <button 
            onClick={() => setShowGreeting(false)}
            className="absolute -top-2 -right-2 bg-slate-900 text-white rounded-full p-1 shadow-lg"
          >
            <X size={12} />
          </button>
          <div className="flex gap-3 items-start">
            <div className="bg-electric-cyan/20 p-2 rounded-full shrink-0">
              <Bot size={16} className="text-electric-cyan" />
            </div>
            <div>
              <p className="text-slate-900 text-xs font-bold leading-tight">Habari! Mimi ni Lexon AI. Je, ungependa kujua jinsi tunavyoweza kukuza faida ya biashara yako leo?</p>
            </div>
          </div>
        </div>
      )}

      {!isOpen ? (
        <button 
          onClick={() => {
            setIsOpen(true);
            setShowGreeting(false);
          }}
          className="w-16 h-16 bg-electric-cyan text-slate-950 rounded-full flex items-center justify-center shadow-[0_0_30px_rgba(34,211,238,0.4)] hover:scale-110 transition-transform relative group"
        >
          <MessageSquare size={28} />
          <span className="absolute -top-1 -right-1 w-4 h-4 bg-red-500 rounded-full border-2 border-[#020617] animate-pulse"></span>
        </button>
      ) : (
        <div className="w-[90vw] md:w-[400px] h-[550px] glass rounded-[2rem] flex flex-col shadow-2xl border border-white/10 overflow-hidden animate-in zoom-in-95 duration-300">
          {/* Header */}
          <div className="bg-gradient-to-r from-electric-cyan to-cyan-600 p-5 flex justify-between items-center">
            <div className="flex items-center gap-3">
              <div className="w-10 h-10 bg-slate-950 rounded-full flex items-center justify-center border border-white/20">
                <Bot className="text-electric-cyan" size={20} />
              </div>
              <div>
                <h3 className="text-slate-950 font-bold text-sm">Lexon AI Assistant</h3>
                <div className="flex items-center gap-1.5">
                  <span className="w-2 h-2 bg-slate-950 rounded-full animate-pulse"></span>
                  <span className="text-slate-900 text-[10px] uppercase font-bold tracking-widest">Active Now</span>
                </div>
              </div>
            </div>
            <button onClick={() => setIsOpen(false)} className="text-slate-950 hover:bg-slate-950/10 p-1.5 rounded-full transition-colors">
              <X size={20} />
            </button>
          </div>

          {/* Messages */}
          <div ref={scrollRef} className="flex-grow overflow-y-auto p-4 space-y-4 bg-slate-950/30 backdrop-blur-sm">
            {messages.map((m, i) => (
              <div key={i} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'}`}>
                <div className={`max-w-[85%] p-3.5 rounded-2xl text-[13px] leading-relaxed ${
                  m.role === 'user' 
                  ? 'bg-electric-cyan text-slate-950 font-medium rounded-tr-none shadow-lg' 
                  : 'bg-white/5 text-slate-200 border border-white/10 rounded-tl-none'
                }`}>
                  {m.text}
                </div>
              </div>
            ))}
            {loading && (
              <div className="flex justify-start">
                <div className="bg-white/5 border border-white/10 p-3 rounded-2xl flex gap-1">
                  <span className="w-1.5 h-1.5 bg-electric-cyan rounded-full animate-bounce"></span>
                  <span className="w-1.5 h-1.5 bg-electric-cyan rounded-full animate-bounce [animation-delay:0.2s]"></span>
                  <span className="w-1.5 h-1.5 bg-electric-cyan rounded-full animate-bounce [animation-delay:0.4s]"></span>
                </div>
              </div>
            )}
          </div>

          {/* Input */}
          <div className="p-4 border-t border-white/5 bg-slate-950/80">
            <div className="flex gap-2">
              <input 
                value={input}
                onChange={(e) => setInput(e.target.value)}
                onKeyDown={(e) => e.key === 'Enter' && handleSend()}
                placeholder="Andika ujumbe hapa..."
                className="flex-grow bg-white/5 border border-white/10 rounded-xl px-4 py-3 text-sm focus:outline-none focus:border-electric-cyan transition-colors text-white placeholder:text-slate-600"
              />
              <button 
                onClick={handleSend}
                disabled={loading || !input.trim()}
                className="bg-electric-cyan text-slate-950 p-3 rounded-xl hover:scale-105 active:scale-95 transition-all disabled:opacity-50"
              >
                <Send size={20} />
