            <div className="mt-3 flex items-center justify-center gap-4">
               <span className="text-[9px] text-slate-500 uppercase tracking-widest font-bold">Lexon Official AI</span>
               <div className="h-1 w-1 bg-slate-700 rounded-full"></div>
               <span className="text-[9px] text-slate-500 uppercase tracking-widest font-bold">CEO: Mohamedi M. Saidi</span>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

