const LexonAI: React.FC = () => {
  const [isOpen, setIsOpen] = useState(false);
  const [showGreeting, setShowGreeting] = useState(false);
  const [messages, setMessages] = useState<{ role: 'user' | 'model'; text: string; isDemo?: boolean }[]>([
    { 
      role: 'model', 
      text: 'Habari! Karibu Lexon AI Assistant. Nitakuuliza maswali 5 pekee kugundua kama biashara yako inapoteza pesa bila wewe kujua.\n\nTayari? Tuiteanze. Unafanya biashara ya aina gani?' 
    }
  ]);
  const [input, setInput] = useState('');
  const [loading, setLoading] = useState(false);
  const [lastLead, setLastLead] = useState<{name: string, text: string} | null>(null);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const timer = setTimeout(() => {
      if (!isOpen) setShowGreeting(true);
    }, 5000);
    return () => clearTimeout(timer);
  }, [isOpen]);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages, loading]);

  const handleSend = async () => {
    if (!input.trim() || loading) return;

    const userMsg = input;
    setInput('');
    setMessages(prev => [...prev, { role: 'user', text: userMsg }]);
    setLoading(true);
    setShowGreeting(false);

    // Alert CEO
    setLastLead({ name: "Mteja", text: userMsg });
    setTimeout(() => setLastLead(null), 6000);

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: messages.map(m => ({
          role: m.role,
          parts: [{ text: m.text }]
        })).concat({ role: 'user', parts: [{ text: userMsg }] }),
        config: {
          systemInstruction: `Wewe ni "Lexon AI Business Diagnostic Assistant" na mtaalamu wa mifumo ya biashara Tanzania. CEO wako ni Mohamedi M. Saidi.

MAJUKUMU YAKO:
1. Usipige soga. Jukumu lako ni kufanya 'Business Audit' kugundua matatizo ya mteja.
2. Fuata hatua hizi MOJA BAADA YA NYINGINE (Uliza swali moja, subiri jibu):
   Step 1: Unafanya biashara ya aina gani? (Tayari umeshauliza)
   Step 2: Unatumia nini kurekodi mauzo/stock? (Daftari, Excel, au System?)
   Step 3: Unaweza kuona report ya mauzo ya leo ndani ya sekunde 10?
   Step 4: Wafanyakazi wangapi wanahusika na stock au mauzo?
   Step 5: Umewahi kupata hasara ya stock au mkanganyiko wa mahesabu?

BAADA YA MASWALI:
- Toa utambuzi mfupi (Conclusion) kwamba biashara yake inapoteza udhibiti.
- Andika neno [SHOW_DEMO] ili uonyeshe Dashboard Demo.
- CTA: Mpe namba ya WhatsApp ya CEO: ${CONTACT_NUMBER}.

SHERIA:
- Tambua lugha ya mteja (Kiswahili/English) na uendelee nayo.
- Kuwa professional na direct.`,
        },
      });

      const aiText = response.text || "Naelewa. Tuendelee...";
      const hasDemo = aiText.includes("[SHOW_DEMO]");
      const cleanText = aiText.replace("[SHOW_DEMO]", "");

      setMessages(prev => [...prev, { role: 'model', text: cleanText, isDemo: hasDemo }]);
    } catch (error) {
      setMessages(prev => [...prev, { role: 'model', text: "Samahani, mtandao una shida. Wasiliana na CEO wetu hapa: " + CONTACT_NUMBER }]);
    } finally {
      setLoading(false);
    }
  };

  return (
    <>
      {/* Real-time Lead Notification for Owner (Internal) */}
      {lastLead && (
        <div className="fixed top-20 right-4 z-[200] bg-slate-900 border-l-4 border-electric-cyan p-4 rounded-xl shadow-2xl animate-in slide-in-from-right-full max-w-[280px]">
          <div className="flex items-center gap-2 mb-1">
            <Bell className="text-electric-cyan animate-ring" size={16} />
            <span className="text-[10px] font-black uppercase text-white">Lead Mpya Kwenye Chat</span>
          </div>
          <p className="text-slate-400 text-[11px] italic">"{lastLead.text}"</p>
        </div>
      )}

      <div className={`fixed z-[100] font-sans transition-all duration-300 ${isOpen ? 'inset-0 md:inset-auto md:bottom-6 md:right-6' : 'bottom-6 right-6'}`}>
        {/* Proactive Greeting */}
        {showGreeting && !isOpen && (
          <div className="absolute bottom-20 right-0 w-72 bg-white p-5 rounded-2xl shadow-2xl border border-electric-cyan/20 animate-in fade-in slide-in-from-bottom-4 group cursor-pointer" onClick={() => setIsOpen(true)}>
            <button onClick={(e) => { e.stopPropagation(); setShowGreeting(false); }} className="absolute -top-2 -right-2 bg-slate-950 text-white rounded-full p-1.5 shadow-lg"><X size={12} /></button>
            <div className="flex gap-4">
              <div className="bg-electric-cyan/20 p-2.5 rounded-full h-fit text-electric-cyan animate-pulse"><Sparkles size={18} /></div>
              <div>
                <p className="text-slate-900 text-[13px] font-black uppercase tracking-tight">Business Audit</p>
                <p className="text-slate-600 text-xs">Je, biashara yako inapoteza pesa? Hebu nikuulize maswali 5 tujue ukweli...</p>
              </div>
            </div>
          </div>
        )}

        {!isOpen ? (
          <button 
            onClick={() => setIsOpen(true)}
            className="w-16 h-16 bg-electric-cyan text-slate-950 rounded-full flex items-center justify-center shadow-[0_0_40px_rgba(34,211,238,0.5)] hover:scale-110 active:scale-95 transition-all relative"
          >
            <MessageSquare size={28} />
            <span className="absolute -top-1 -right-1 w-5 h-5 bg-red-500 rounded-full border-2 border-slate-950 animate-pulse flex items-center justify-center text-[10px] font-black text-white">1</span>
          </button>
        ) : (
          <div className="w-full h-full md:w-[420px] md:h-[650px] bg-[#020617] md:glass md:rounded-[2.5rem] flex flex-col shadow-2xl border-white/10 overflow-hidden animate-in zoom-in-95">
            {/* Header */}
            <div className="bg-electric-cyan p-5 md:p-6 flex justify-between items-center shrink-0">
              <div className="flex items-center gap-3">
