import React, { useState, useEffect } from 'react';
import { Language } from './types';
import Header from './components/Header';
import Hero from './components/Hero';
import Opportunity from './components/Opportunity';
import Solutions from './components/Solutions';
import About from './components/About';
import IdealState from './components/IdealState';
import TriadModel from './components/TriadModel';
import ROICalculator from './components/ROICalculator';
import TrustAuthority from './components/TrustAuthority';
import News from './components/News';
import WhyLexon from './components/WhyLexon';
import Footer from './components/Footer';
import ChatAssistant from './components/ChatAssistant';
import ContactModal from './components/ContactModal';
import BlogPost from './components/BlogPost';

const App: React.FC = () => {
  const [lang, setLang] = useState<Language>(Language.EN);
  const [isContactOpen, setIsContactOpen] = useState(false);
  const [currentPath, setCurrentPath] = useState<string>('home'); // 'home' or 'blog/[slug]'

  // Handle browser back button
  useEffect(() => {
    const handlePopState = () => {
      const path = window.location.hash.replace('#', '') || 'home';
      setCurrentPath(path);
    };
    window.addEventListener('popstate', handlePopState);
    // Initial check
    handlePopState();
    return () => window.removeEventListener('popstate', handlePopState);
  }, []);

  const navigateTo = (path: string) => {
    window.location.hash = path;
    setCurrentPath(path);
    window.scrollTo(0, 0);
  };

  const toggleLang = () => {
    setLang(prev => prev === Language.EN ? Language.SW : Language.EN);
  };

  const openContact = () => setIsContactOpen(true);
  const closeContact = () => setIsContactOpen(false);

  if (currentPath.startsWith('blog/')) {
    const slug = currentPath.split('/')[1];
    return (
      <div className="min-h-screen bg-[#020617] text-slate-100 flex flex-col">
        <Header lang={lang} onToggleLang={toggleLang} onOpenContact={openContact} />
        <main className="flex-grow pt-24">
          <BlogPost slug={slug} lang={lang} onBack={() => navigateTo('home')} onContact={openContact} />
        </main>
        <Footer lang={lang} onOpenContact={openContact} />
        <ChatAssistant />
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-[#020617] text-slate-100 selection:bg-cyan-500 selection:text-white flex flex-col scroll-smooth">
      <Header lang={lang} onToggleLang={toggleLang} onOpenContact={openContact} />

      <main className="flex-grow">
        <Hero lang={lang} onOpenContact={openContact} />
        <div id="opportunity"><Opportunity lang={lang} /></div>
        <div id="solutions"><Solutions lang={lang} onOpenContact={openContact} /></div>
        <div id="about"><About lang={lang} /></div>
        <IdealState lang={lang} />
        <TriadModel lang={lang} />
        <div id="roi"><ROICalculator lang={lang} onOpenContact={openContact} /></div>
        <WhyLexon lang={lang} />
        <News lang={lang} onNavigate={navigateTo} />
        <TrustAuthority />
      </main>

      <Footer lang={lang} onOpenContact={openContact} />

      <ContactModal 
        isOpen={isContactOpen} 
        onClose={closeContact} 
        lang={lang} 
      />

      <ChatAssistant />
    </div>
  );
};

export default App;

