  const [isOpen, setIsOpen] = useState(false);
  const [showGreeting, setShowGreeting] = useState(false);
  const [messages, setMessages] = useState<{ role: 'user' | 'model'; text: string; isDemo?: boolean }[]>([
    { 
      role: 'model', 
      text: 'Habari! Karibu Lexon Tech. Mimi ni msaidizi wako wa mauzo (AI Sales Assistant). Unatafuta mfumo gani wa kuboresha biashara yako leo?' 
    }
  ]);
  const [input, setInput] = useState('');
  const [loading, setLoading] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const timer = setTimeout(() => {
      if (!isOpen) setShowGreeting(true);
    }, 6000);
    return () => clearTimeout(timer);
  }, [isOpen]);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages, loading]);

  const handleSend = async () => {
    if (!input.trim() || loading) return;

    const userMsg = input;
    setInput('');
    setMessages(prev => [...prev, { role: 'user', text: userMsg }]);
    setLoading(true);
    setShowGreeting(false);

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: messages.map(m => ({
          role: m.role,
          parts: [{ text: m.text }]
        })).concat({ role: 'user', parts: [{ text: userMsg }] }),
        config: {
          systemInstruction: `Wewe ni "Lexon AI Sales Bot" (WhatsApp-style Assistant).
JUKUMU LAKO: Kusaidia wateja kuelewa bidhaa na kufunga mauzo.

INVENTORY DATA (Sheet):
${JSON.stringify(INVENTORY)}

CONVERSATION FLOW:
Stage 1 - Greet (Already done).
Stage 2 - Inquiry: Chambua mteja anataka nini.
Stage 3 - Response: Kama bidhaa ipo kwenye INVENTORY, mpe jina, bei, na maelezo kwa Kiswahili cha kuvutia. Kama haipo, sema "Samahani hiyo haipo kwa sasa lakini mhudumu atakucheki."
Stage 4 - Closing: Mteja akionyesha nia, muombe namba yake ya WhatsApp na Location ili timu ya ufundi impe "Free Audit".

SHERIA:
- Tumia Kiswahili fasaha (au English mteja akianza).
- Usipige soga zisizo na maana, lengo ni kuuza mifumo ya Lexon.
- Kama mteja anataka Demo, andika neno [SHOW_DEMO] kwenye ujumbe wako.`,
        },
      });

      const aiText = response.text || "Naelewa. Hebu nikupe maelezo zaidi...";
      const hasDemo = aiText.includes("[SHOW_DEMO]");
      const cleanText = aiText.replace("[SHOW_DEMO]", "");

      setMessages(prev => [...prev, { role: 'model', text: cleanText, isDemo: hasDemo }]);
    } catch (error) {
      setMessages(prev => [...prev, { role: 'model', text: "Samahani, naona mtandao una shida. Tafadhali wasiliana nasi moja kwa moja: " + CONTACT_NUMBER }]);
    } finally {
      setLoading(false);
    }
  };

  return (
    <>
      <div className={`fixed z-[100] font-sans transition-all duration-500 ${isOpen ? 'inset-0 md:inset-auto md:bottom-6 md:right-6' : 'bottom-6 right-6'}`}>
        {showGreeting && !isOpen && (
          <div className="absolute bottom-20 right-0 w-72 bg-white p-5 rounded-2xl shadow-2xl border border-electric-cyan/20 animate-in fade-in slide-in-from-bottom-4 group cursor-pointer" onClick={() => setIsOpen(true)}>
             <button onClick={(e) => { e.stopPropagation(); setShowGreeting(false); }} className="absolute -top-2 -right-2 bg-slate-950 text-white rounded-full p-1.5 shadow-lg"><X size={12} /></button>
             <div className="flex gap-4">
               <div className="bg-electric-cyan/20 p-2.5 rounded-full h-fit text-electric-cyan animate-pulse"><Bot size={18} /></div>
               <div>
                 <p className="text-slate-900 text-[13px] font-black uppercase">Unatafuta Mfumo?</p>
                 <p className="text-slate-600 text-xs">Mimi ni Lexon AI Sales Bot. Naweza kukusaidia kuchagua mfumo sahihi sasa hivi!</p>
               </div>
             </div>
          </div>
        )}

        {!isOpen ? (
          <button 
            onClick={() => setIsOpen(true)}
            className="w-16 h-16 bg-electric-cyan text-slate-950 rounded-full flex items-center justify-center shadow-[0_0_40px_rgba(34,211,238,0.5)] hover:scale-110 active:scale-95 transition-all relative"
          >
            <Bot size={28} />
            <span className="absolute -top-1 -right-1 w-5 h-5 bg-red-500 rounded-full border-2 border-slate-950 animate-pulse flex items-center justify-center text-[10px] font-black text-white">1</span>
          </button>
        ) : (
          <div className="w-full h-full md:w-[420px] md:h-[650px] bg-[#020617] md:glass md:rounded-[2.5rem] flex flex-col shadow-2xl border border-white/10 overflow-hidden animate-in zoom-in-95 duration-300">
            <div className="bg-electric-cyan p-5 md:p-6 flex justify-between items-center shrink-0 border-b border-black/5">
              <div className="flex items-center gap-3">
                <div className="w-12 h-12 bg-slate-950 rounded-2xl flex items-center justify-center border border-white/20"><Bot className="text-electric-cyan" size={24} /></div>
                <div>
                  <h3 className="text-slate-950 font-black text-sm uppercase tracking-widest leading-none">Lexon AI Sales Bot</h3>
                  <div className="flex items-center gap-1.5 mt-1"><span className="w-2 h-2 bg-green-900 rounded-full animate-pulse"></span><span className="text-slate-900 text-[10px] uppercase font-black tracking-widest">Always Online</span></div>
                </div>
              </div>
              <button onClick={() => setIsOpen(false)} className="text-slate-950 hover:bg-slate-950/10 p-2 rounded-full"><X size={24} /></button>
            </div>

            <div ref={scrollRef} className="flex-grow overflow-y-auto p-5 space-y-6 bg-slate-950/40 custom-scrollbar">
              {messages.map((m, i) => (
                <div key={i} className={`flex flex-col ${m.role === 'user' ? 'items-end' : 'items-start'}`}>
                  <div className={`max-w-[85%] p-4 rounded-2xl text-[14px] leading-relaxed shadow-lg ${
                    m.role === 'user' 
                    ? 'bg-electric-cyan text-slate-950 font-bold rounded-tr-none' 
                    : 'bg-white/10 text-slate-100 border border-white/10 rounded-tl-none backdrop-blur-md'
                  }`}>
                    {m.text.split('\n').map((line, idx) => <p key={idx} className={idx > 0 ? 'mt-2' : ''}>{line}</p>)}
                    {m.isDemo && <MiniDemoView />}
                  </div>
                </div>
              ))}
              {loading && (
                <div className="flex justify-start">
                  <div className="bg-white/5 border border-white/10 p-4 rounded-2xl flex gap-1.5 items-center">
                    <span className="w-1.5 h-1.5 bg-electric-cyan rounded-full animate-bounce"></span>
                    <span className="w-1.5 h-1.5 bg-electric-cyan rounded-full animate-bounce [animation-delay:0.2s]"></span>
                    <span className="w-1.5 h-1.5 bg-electric-cyan rounded-full animate-bounce [animation-delay:0.4s]"></span>
                  </div>
                </div>
              )}
            </div>

            <div className="p-5 border-t border-white/5 bg-slate-950/90 pb-10 md:pb-6">
              <div className="flex gap-3">
                <input 
                  value={input}
                  onChange={(e) => setInput(e.target.value)}
                  onKeyDown={(e) => e.key === 'Enter' && handleSend()}
                  placeholder="Andika ujumbe wako..."
                  className="flex-grow bg-white/5 border border-white/10 rounded-2xl px-5 py-4 text-sm focus:border-electric-cyan outline-none text-white transition-all placeholder:text-slate-600"
                />
                <button 
                  onClick={handleSend} 
                  disabled={loading || !input.trim()} 
                  className="bg-electric-cyan text-slate-950 p-4 rounded-2xl hover:scale-105 active:scale-95 transition-all disabled:opacity-50"
                >
                  <Send size={24} />
                </button>
              </div>
            </div>
          </div>
        )}
      </div>
    </>
  );
};

export default LexonAI;
